import { Hound, InMemoryStorage } from 'hound/';

const hound = Hound.create({
  db: new InMemoryStorage(),
});

hound.on('user.welcome', async (ctx) => {
  ctx.logger(`Sending welcome email to ${ctx.data.email}`);
});

await hound.start();
hound.emit('user.welcome', { email: 'leo@example.com' });

